const columnWidth = $derived.by(() => {
  if (containerWidth === 0) return 0;
  return (containerWidth - gap * (columns - 1)) / columns;
});

// Position items in columns
interface PositionedItem {
  item: T;
  index: number;
  x: number;
  y: number;
  height: number;
  column: number;
}

const positionedItems = $derived.by((): PositionedItem[] => {
  if (columnWidth === 0) return [];

  const columnHeights = new Array(columns).fill(0);
  const positioned: PositionedItem[] = [];

  for (let i = 0; i < items.length; i++) {
    // Find shortest column
    const shortestColumn = columnHeights.indexOf(Math.min(...columnHeights));
    const itemHeight = getItemHeight ? getItemHeight(items[i], i) : 200;

    positioned.push({
      item: items[i],
      index: i,
      x: shortestColumn * (columnWidth + gap),
      y: columnHeights[shortestColumn],
      height: itemHeight,
      column: shortestColumn
    });

    columnHeights[shortestColumn] += itemHeight + gap;
  }

  return positioned;
});

import { error } from "@sveltejs/kit";
import type { EntryGenerator } from "./$types.js";
import type { Component } from "svelte";
import { blocks } from "../../../../__registry__/blocks.js";
import { blockMeta } from "$lib/registry/registry-block-meta.js";

export const prerender = true;

export const entries: EntryGenerator = () => blocks.map((view) => ({ view }));

export async function load({ params }) {
	let comp: { default: Component } | undefined;

	if (params.view.startsWith("demo-") || params.view.startsWith("calendar-")) {
		comp = await import(`../../../../lib/registry/blocks/${params.view}.svelte`);
	} else {
		comp = await import(`../../../../lib/registry/blocks/${params.view}/+page.svelte`);
	}

	if (!comp) error(404, "Block not found");

	const meta = blockMeta[params.view as keyof typeof blockMeta];

	return { component: comp.default, meta: { ...meta, name: params.view } };
}

import { attachRef, type ReadableBoxedValues } from "svelte-toolbelt";
import type { RefAttachment, WithRefOpts } from "$lib/internal/types.js";
import { createBitsAttrs } from "$lib/internal/attrs.js";

const aspectRatioAttrs = createBitsAttrs({
	component: "aspect-ratio",
	parts: ["root"],
});

interface AspectRatioRootStateOpts extends WithRefOpts, ReadableBoxedValues<{ ratio: number }> {}

export class AspectRatioRootState {
	static create(opts: AspectRatioRootStateOpts) {
		return new AspectRatioRootState(opts);
	}

	readonly opts: AspectRatioRootStateOpts;
	readonly attachment: RefAttachment;

	constructor(opts: AspectRatioRootStateOpts) {
		this.opts = opts;
		this.attachment = attachRef(this.opts.ref);
	}

	readonly props = $derived.by(
		() =>
			({
				id: this.opts.id.current,
				style: {
					position: "absolute",
					top: 0,
					right: 0,
					bottom: 0,
					left: 0,
				},
				[aspectRatioAttrs.root]: "",
				...this.attachment,
			}) as const
	);
}

export function destroy_effect(effect, remove_dom = true) {
	var removed = false;

	if (
		(remove_dom || (effect.f & HEAD_EFFECT) !== 0) &&
		effect.nodes !== null &&
		effect.nodes.end !== null
	) {
		remove_effect_dom(effect.nodes.start, /** @type {TemplateNode} */ (effect.nodes.end));
		removed = true;
	}

	effect.f |= DESTROYING;
	destroy_effect_children(effect, remove_dom && !removed);
	remove_reactions(effect, 0);

	var transitions = effect.nodes && effect.nodes.t;

	if (transitions !== null) {
		for (const transition of transitions) {
			transition.stop();
		}
	}

	execute_effect_teardown(effect);

	effect.f ^= DESTROYING;
	effect.f |= DESTROYED;

	var parent = effect.parent;

	// If the parent doesn't have any children, then skip this work altogether
	if (parent !== null && parent.first !== null) {
		unlink_effect(effect);
	}

	if (DEV) {
		effect.component_function = null;
	}

	// `first` and `child` are nulled out in destroy_effect_children
	// we don't null out `parent` so that error propagation can work correctly
	effect.next =
		effect.prev =
		effect.teardown =
		effect.ctx =
		effect.deps =
		effect.fn =
		effect.nodes =
		effect.ac =
		effect.b =
			null;
}

import { isFunction, isHTMLElement, sleep } from '$lib/internal/helpers/index.js';
import { tick } from 'svelte';

export type FocusTarget = string | HTMLElement | SVGElement | null;
export type FocusProp = FocusTarget | ((defaultEl?: HTMLElement | null) => FocusTarget);

type HandleFocusArgs = {
	prop?: FocusProp;
	defaultEl: HTMLElement | null;
};

export async function handleFocus(args: HandleFocusArgs): Promise<void> {
	const { prop, defaultEl } = args;

	await Promise.all([sleep(1), tick]);

	if (prop === undefined) {
		defaultEl?.focus();
		return;
	}

	const returned = isFunction(prop) ? prop(defaultEl) : prop;

	if (typeof returned === 'string') {
		// Get el by selector, focus it
		const el = document.querySelector(returned);
		if (!isHTMLElement(el)) return;
		el.focus();
	} else if (isHTMLElement(returned)) {
		// Focus it
		returned.focus();
	}
}

export class DataTypeahead {
	readonly #opts: DataTypeaheadOpts;
	readonly #candidateValues = $derived.by(() => this.#opts.candidateValues());

	#search: WritableBox<string>;

	constructor(opts: DataTypeaheadOpts) {
		this.#opts = opts;
		this.#search = boxAutoReset("", {
			afterMs: 1000,
			getWindow: this.#opts.getWindow,
		});

		this.handleTypeaheadSearch = this.handleTypeaheadSearch.bind(this);
		this.resetTypeahead = this.resetTypeahead.bind(this);
	}

	handleTypeaheadSearch(key: string) {
		if (!this.#opts.enabled() || !this.#candidateValues.length) return;

		this.#search.current = this.#search.current + key;
		const currentItem = this.#opts.getCurrentItem();
		const currentMatch = this.#candidateValues.find((item) => item === currentItem) ?? "";
		const values = this.#candidateValues.map((item) => item ?? "");
		const nextMatch = getNextMatch(values, this.#search.current, currentMatch);
		const newItem = this.#candidateValues.find((item) => item === nextMatch);
		if (newItem) {
			this.#opts.onMatch(newItem);
		}
		return newItem;
	}

	resetTypeahead() {
		this.#search.current = "";
	}
}

